create extension if not exists pgcrypto;
create table if not exists public.profiles(id uuid primary key default gen_random_uuid(),name text not null default 'مفيد مهيوب عبدالسلام الشميري',role text default '',email text default '',phone text default '',location text default '',headline text default '',bio text default '',photo_url text default '',cv_url text default '',years text default '',projects_count text default '',certificates_count text default '',commitment text default '',created_at timestamptz default now(),updated_at timestamptz default now());
create table if not exists public.experiences(id uuid primary key default gen_random_uuid(),period text default '',title text default '',org text default '',description text default '',sort_order int default 0);
create table if not exists public.education(id uuid primary key default gen_random_uuid(),period text default '',title text default '',org text default '',description text default '',sort_order int default 0);
create table if not exists public.certificates(id uuid primary key default gen_random_uuid(),title text default '',file_url text default '',sort_order int default 0);
create table if not exists public.skills(id uuid primary key default gen_random_uuid(),category text default '',items jsonb default '[]'::jsonb,sort_order int default 0);
create table if not exists public.projects(id uuid primary key default gen_random_uuid(),title text default '',description text default '',sort_order int default 0);
alter table public.profiles enable row level security;alter table public.experiences enable row level security;alter table public.education enable row level security;alter table public.certificates enable row level security;alter table public.skills enable row level security;alter table public.projects enable row level security;
create policy "public read profiles" on public.profiles for select using(true);create policy "public read experiences" on public.experiences for select using(true);create policy "public read education" on public.education for select using(true);create policy "public read certificates" on public.certificates for select using(true);create policy "public read skills" on public.skills for select using(true);create policy "public read projects" on public.projects for select using(true);
create policy "auth manage profiles" on public.profiles for all to authenticated using(true) with check(true);create policy "auth manage experiences" on public.experiences for all to authenticated using(true) with check(true);create policy "auth manage education" on public.education for all to authenticated using(true) with check(true);create policy "auth manage certificates" on public.certificates for all to authenticated using(true) with check(true);create policy "auth manage skills" on public.skills for all to authenticated using(true) with check(true);create policy "auth manage projects" on public.projects for all to authenticated using(true) with check(true);
insert into public.profiles(name,role,email,phone,location,headline,bio,years,projects_count,certificates_count,commitment) select 'مفيد مهيوب عبدالسلام الشميري','مشرف طلبات | كاشير | محضر طلبات','abwtrkyalshmyry027@gmail.com','0533946458','الدمام، المملكة العربية السعودية','موظف متخصص في إدارة الطلبات وخدمة العملاء والعمليات اليومية','أتميز بالدقة، سرعة التعلم، والقدرة على العمل تحت الضغط. أسعى للانضمام لجهة احترافية أساهم فيها بتطوير الأداء وتحسين سير العمل.','7+','5+','7+','100%' where not exists(select 1 from public.profiles);
insert into storage.buckets(id,name,public) values('cv-files','cv-files',true) on conflict(id) do nothing;
create policy "public read cv files" on storage.objects for select using(bucket_id='cv-files');create policy "auth upload cv files" on storage.objects for insert to authenticated with check(bucket_id='cv-files');create policy "auth update cv files" on storage.objects for update to authenticated using(bucket_id='cv-files') with check(bucket_id='cv-files');create policy "auth delete cv files" on storage.objects for delete to authenticated using(bucket_id='cv-files');
